class Solution:
    def countOdds(self, low, high):
        return sum(1 for x in range(low, high + 1) if x % 2 == 1)

solutions.python:
class Solution:
    def countOdds(self, low, high):
        return (high + 1) // 2 - low // 2

solutions.javascript:
var countOdds = function(low, high) {
    return Math.floor((high + 1) / 2) - Math.floor(low / 2);
};
